/* echo.c — demo program: prints "hello world" via service vector
 * Receives ctx (service vector pointer), returns 0.
 */

int main(int ctx) {
    int *vec;
    int (*putchar_fn)();
    char *msg;
    vec = ctx;
    putchar_fn = vec[0];    /* slot 0 = svc_putchar */
    msg = "hello world\n";
    while (*msg) {
        putchar_fn(*msg);
        msg = msg + 1;
    }
    return 0;
}

/* failtest.c — demo program: prints error message and returns nonzero RC
 * Demonstrates nonzero return code handling.
 */

int main(int ctx) {
    int *vec;
    int (*putchar_fn)();
    char *msg;
    vec = ctx;
    putchar_fn = vec[0];    /* slot 0 = svc_putchar */
    msg = "something went wrong\n";
    while (*msg) {
        putchar_fn(*msg);
        msg = msg + 1;
    }
    return 12;
}

/* cat.c — demo program: echoes input characters until 'q'
 * Demonstrates interactive I/O through the service vector.
 */

int main(int ctx) {
    int *vec;
    int (*putchar_fn)();
    int (*getchar_fn)();
    int ch;
    vec = ctx;
    putchar_fn = vec[0];    /* slot 0 = svc_putchar */
    getchar_fn = vec[1];    /* slot 1 = svc_getchar */
    ch = getchar_fn();
    while (ch != 113) {      /* 113 = 'q' */
        putchar_fn(ch);
        ch = getchar_fn();
    }
    return 0;
}

